// Revenue recognition: turn a completed work order (forge.completed)
// into a balanced ledger.entry Event envelope. This is the orchestration
// seam — keeping this mapping in n8n decouples Forge from accounting.
const evt = $json;
const e = evt.payload ?? evt;

const lines = [
  { account: '1100-accounts-receivable', direction: 'debit',  amount_minor: e.gross_minor },
  { account: '4000-revenue',             direction: 'credit', amount_minor: e.net_minor },
];
if ((e.tax_minor ?? 0) > 0) {
  lines.push({ account: '2200-tax-payable', direction: 'credit', amount_minor: e.tax_minor });
}

return {
  json: {
    subject: 'ledger.entry',
    schema_version: 1,
    source: 'n8n:sale-to-posting',
    correlation_id: evt.correlation_id ?? null,
    payload: {
      entry_id: e.entry_id,
      currency: e.currency,
      memo: `sale ${e.sku} x${e.quantity} (wo ${e.work_order_id})`,
      lines,
    },
  },
};
